namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private readonly List<Notification> _notifications;
    private int _nextId;

    public NotificationService()
    {
        _notifications =
        [
            new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-30)),
            new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-20)),
            new(3, "New feature: dark mode is available.", DateTime.UtcNow.AddMinutes(-10)),
        ];
        _nextId = 4;
    }

    /// <summary>Returns all notifications available at this moment.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
        => Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());

    /// <summary>Returns only notifications newer than <paramref name="since"/>.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
    {
        // Simulate a new notification arriving roughly every 10 seconds.
        if (_notifications.Count == 0 || DateTime.UtcNow - _notifications[^1].Timestamp > TimeSpan.FromSeconds(10))
        {
            var id = _nextId++;
            _notifications.Add(new(id, $"New event #{id} just happened.", DateTime.UtcNow));
        }

        var newer = _notifications
            .Where(n => n.Timestamp > since)
            .OrderByDescending(n => n.Timestamp)
            .ToList();

        return Task.FromResult(newer);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService Svc
@inject PersistentComponentState PersistentState
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span style="background:#0d6efd;color:#fff;border-radius:999px;padding:2px 10px;font-size:0.6em;vertical-align:middle;">
        @_notifications.Count
    </span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul>
        @foreach (var n in _notifications)
        {
            <li>
                <strong>@n.Timestamp.ToString("HH:mm:ss")</strong> &mdash; @n.Message
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = [];
    private CancellationTokenSource? _cts;
    private PersistingComponentStateSubscription _persistSub;
    private DateTime _latestTimestamp;

    protected override async Task OnInitializedAsync()
    {
        _persistSub = PersistentState.RegisterOnPersisting(PersistData);

        // Try to restore data persisted during SSR so we don't fetch twice.
        if (PersistentState.TryTakeFromJson<List<Notification>>("notifications", out var restored) && restored is not null)
        {
            _notifications = restored;
        }
        else
        {
            _notifications = await Svc.GetNotificationsAsync();
        }

        _latestTimestamp = _notifications.Count > 0
            ? _notifications.Max(n => n.Timestamp)
            : DateTime.UtcNow;
    }

    private Task PersistData()
    {
        PersistentState.PersistAsJson("notifications", _notifications);
        return Task.CompletedTask;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender only fires when the component is interactive,
        // so the polling loop will never start during static SSR.
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var newer = await Svc.GetNotificationsSinceAsync(_latestTimestamp);
                if (newer.Count > 0)
                {
                    _notifications.InsertRange(0, newer);
                    _latestTimestamp = newer.Max(n => n.Timestamp);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        _persistSub.Dispose();

        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

